// dsmem-latency/main.cu
// Distributed Shared Memory (DSMEM) Cross-SM Latency Benchmark
//
// On Hopper, a Thread Block Cluster groups multiple blocks into one CGA.
// Blocks within a cluster can read each other's shared memory via
// ld.shared::cluster (generated by cluster.map_shared_rank + dereference).
//
// This benchmark measures the *latency* of that cross-SM SMEM access path
// using serialised pointer chasing: each load's address depends on the
// previous load's result, so loads cannot overlap.
//
// Chain layout: every thread has its own independent circular sub-chain
// with stride = blockDim.x, so the whole warp stays active with no
// divergence.  Measured kernel time / iters = average latency per load.
//
// Sweeps:
//   1. Distance sweep   – dist 0 (local baseline) to CS-1, fixed SMEM/threads
//   2. Thread count     – 32 to 1024 threads/block, CS=4 dist=1
//   3. Chain length     – vary SMEM size, CS=4 dist=1 block=32
//
// Requires: CUDA 12.0+, Hopper GPU (H100/H200, sm_90a)

#include "../MeasurementSeries.hpp"
#include "../gpu-error.h"
#include <cooperative_groups.h>
#include <iomanip>
#include <iostream>
#include <vector>

namespace cg = cooperative_groups;
using namespace std;

static uint32_t *d_sink   = nullptr;
static volatile bool secretlyFalse = false;

// ─── kernel ───────────────────────────────────────────────────────────────────
//
// Each block builds per-thread circular chains in its own SMEM, then every
// thread serially pointer-chases through the *remote* block's SMEM.
//
//   smem[i]  =  i + bdim   (if i + bdim < chain_len)
//            =  tid         (wrap-back to thread's chain head)
//
// Thread tid's chain:  tid → tid+bdim → tid+2·bdim → … → tid
// Chain length per thread:  chain_len / bdim
template <int CLUSTER_SIZE>
__global__ void __cluster_dims__(CLUSTER_SIZE, 1, 1)
dsmem_latency_kernel(uint32_t *__restrict__ sink,
                     int chain_len,   // uint32 elements in shared mem
                     int iters,       // pointer-chase steps per thread
                     int distance,    // ring distance to remote block (0 = self)
                     bool sf)
{
    cg::cluster_group cluster = cg::this_cluster();
    extern __shared__ uint32_t smem[];

    const int tid         = (int)threadIdx.x;
    const int bdim        = (int)blockDim.x;
    const int my_rank     = (int)cluster.block_rank();
    const int remote_rank = (my_rank + distance) % CLUSTER_SIZE;

    // Initialise local SMEM with per-thread stride-bdim circular chains.
    for (int i = tid; i < chain_len; i += bdim)
        smem[i] = (uint32_t)(i + bdim < chain_len ? i + bdim : tid);

    // Wait until all blocks in the cluster have populated their SMEM before
    // any block begins cross-SM reads.
    cluster.sync();

    // Map remote block's shared memory (generates ld.shared::cluster).
    // When distance == 0, remote_rank == my_rank → accesses local SMEM
    // via the cluster path, providing a same-SM baseline.
    uint32_t *remote = cluster.map_shared_rank(smem, remote_rank);

    // Serial pointer chase – data dependency prevents load overlap.
    uint32_t idx = (uint32_t)tid;
#pragma unroll 1
    for (int it = 0; it < iters; ++it)
        idx = remote[idx];

    // Critical: every block must stay alive until all peers finish reading,
    // otherwise an early-exiting block's SMEM is reclaimed by the SM.
    cluster.sync();

    if (sf) sink[blockIdx.x * bdim + tid] = idx;
}

// ─── measurement helper ───────────────────────────────────────────────────────
// Returns median latency per pointer-chase step in nanoseconds.
template <typename LaunchFn>
double measure_lat_ns(LaunchFn launch, int iters)
{
    cudaGetLastError();
    launch();
    GPU_ERROR(cudaDeviceSynchronize());

    MeasurementSeries t;
    cudaEvent_t ev0, ev1;
    GPU_ERROR(cudaEventCreate(&ev0));
    GPU_ERROR(cudaEventCreate(&ev1));
    for (int r = 0; r < 31; ++r) {
        GPU_ERROR(cudaEventRecord(ev0));
        launch();
        GPU_ERROR(cudaEventRecord(ev1));
        GPU_ERROR(cudaEventSynchronize(ev1));
        float ms = 0.f;
        GPU_ERROR(cudaEventElapsedTime(&ms, ev0, ev1));
        t.add((double)ms * 1e-3);
    }
    GPU_ERROR(cudaEventDestroy(ev0));
    GPU_ERROR(cudaEventDestroy(ev1));

    return t.median() / iters * 1e9;   // seconds → ns per step
}

// ─── per-config driver ────────────────────────────────────────────────────────
struct DevInfo {
    int    num_sms;
    int    max_thr_per_sm;
    size_t max_smem_per_block;
    double clock_ghz;    // SM clock in GHz (from cudaDeviceProp::clockRate kHz)
};

template <int CS>
void do_measure(const DevInfo &di,
                int block_size, size_t smem_bytes, int distance, int iters)
{
    const int chain_len    = (int)(smem_bytes / sizeof(uint32_t));
    const int num_clusters = di.num_sms / CS;
    if (num_clusters == 0) return;
    if (chain_len < block_size) return;   // need ≥ 1 element per thread

    const int    num_blocks = num_clusters * CS;
    const double occ        = (double)block_size / di.max_thr_per_sm * 100.0;

    GPU_ERROR(cudaFuncSetAttribute(dsmem_latency_kernel<CS>,
        cudaFuncAttributeMaxDynamicSharedMemorySize, (int)smem_bytes));

    double lat_ns  = measure_lat_ns([&]() {
        dsmem_latency_kernel<CS><<<num_blocks, block_size, smem_bytes>>>(
            d_sink, chain_len, iters, distance, (bool)secretlyFalse);
    }, iters);
    double lat_cyc = lat_ns * di.clock_ghz;

    const char *label = (distance == 0) ? " (local)" : "        ";
    cout << fixed
         << "  CS=" << CS
         << "  dist=" << distance << label
         << "  threads=" << setw(4) << block_size
         << "  occ=" << setprecision(0) << setw(3) << occ << "%"
         << "  smem=" << setw(3) << smem_bytes / 1024 << "kB"
         << "   |"
         << setprecision(2) << setw(8) << lat_ns  << " ns"
         << "  " << setprecision(1) << setw(6) << lat_cyc << " cyc"
         << "\n";
    cout.flush();
}

// Dispatches runtime CS → compile-time template argument.
void run_config(int cs, const DevInfo &di,
                int block_size, size_t smem_bytes, int distance, int iters)
{
    if (block_size > di.max_thr_per_sm)     return;
    if (smem_bytes > di.max_smem_per_block) return;
    switch (cs) {
        case 2: do_measure<2>(di, block_size, smem_bytes, distance, iters); break;
        case 4: do_measure<4>(di, block_size, smem_bytes, distance, iters); break;
        case 8: do_measure<8>(di, block_size, smem_bytes, distance, iters); break;
        default: break;
    }
}

// ─── main ─────────────────────────────────────────────────────────────────────
int main()
{
    int dev;
    cudaDeviceProp prop;
    GPU_ERROR(cudaGetDevice(&dev));
    GPU_ERROR(cudaGetDeviceProperties(&prop, dev));

    if (prop.major < 9) {
        cerr << "ERROR: Hopper GPU (sm_90+) required for Distributed SMEM.\n"
             << "  Detected: " << prop.name
             << " (sm_" << prop.major << prop.minor << ")\n";
        return 1;
    }

    DevInfo di;
    di.num_sms            = prop.multiProcessorCount;
    di.max_thr_per_sm     = prop.maxThreadsPerMultiProcessor;
    di.max_smem_per_block = prop.sharedMemPerBlockOptin;
    di.clock_ghz          = prop.clockRate * 1e-6;   // kHz → GHz

    const int    iters        = 10000;
    const size_t fixed_smem   = 64 * 1024;
    const int    fixed_threads = 32;             // 1 warp; minimal contention

    cout << "=== Distributed SMEM Cross-SM Latency Benchmark ===\n"
         << "GPU             : " << prop.name << "\n"
         << "SMs             : " << di.num_sms << "\n"
         << "Max threads/SM  : " << di.max_thr_per_sm << "\n"
         << "Max SMEM/block  : " << di.max_smem_per_block / 1024 << " kB\n"
         << "SM clock        : " << fixed << setprecision(3)
                                 << di.clock_ghz << " GHz\n"
         << "Chain iters     : " << iters << "\n\n";

    // d_sink must accommodate the largest possible launch:
    // num_sms blocks × 1024 threads/block × sizeof(uint32_t)
    GPU_ERROR(cudaMalloc(&d_sink,
        (size_t)di.num_sms * 1024 * sizeof(uint32_t)));
    GPU_ERROR(cudaMemset(d_sink, 0,
        (size_t)di.num_sms * 1024 * sizeof(uint32_t)));

    auto sep = [](const char *title) {
        cout << "── " << title << "\n"
             << "  " << string(72, '-') << "\n";
    };

    // ── Sweep 1: distance sweep ──────────────────────────────────────────────
    // dist=0: self-read via cluster path (local SMEM baseline)
    // dist=1: adjacent SM in cluster ring
    // dist>1: farther ring-neighbors
    // On Hopper SMs within one GPC share a crossbar; topology effects may
    // appear at larger distances when CS > 2.
    sep("Sweep 1: distance sweep  (block=32, SMEM=64kB)");
    for (int cs : {2, 4, 8}) {
        for (int dist = 0; dist < cs; ++dist)
            run_config(cs, di, fixed_threads, fixed_smem, dist, iters);
        cout << "\n";
    }

    // ── Sweep 2: thread count sweep ──────────────────────────────────────────
    // Tests whether increasing the number of concurrent ld.shared::cluster
    // requests (more threads → more in-flight loads per warp) raises latency
    // through contention on the cross-SM fabric or SMEM ports.
    sep("Sweep 2: thread count sweep  (CS=4, dist=1, SMEM=64kB)");
    for (int t : {32, 64, 128, 256, 512, 1024})
        run_config(4, di, t, fixed_smem, 1, iters);
    cout << "\n";

    // ── Sweep 3: chain length sweep ──────────────────────────────────────────
    // Varies the SMEM working set from 4 kB to the Hopper maximum (228 kB).
    // On a pure-SMEM path latency should be flat; any step change could
    // indicate micro-architecture effects (banking, pipeline stages, etc.).
    sep("Sweep 3: chain length sweep  (CS=4, dist=1, block=32)");
    const vector<int> smem_kbs = {4, 8, 16, 32, 64, 96, 128, 160, 192, 228};
    for (int kb : smem_kbs)
        run_config(4, di, fixed_threads, (size_t)kb * 1024, 1, iters);
    cout << "\n";

    GPU_ERROR(cudaFree(d_sink));
    return 0;
}
